module ring_counter(obf_clk, reset, count);  

    input  obf_clk;  
    input  reset;  
    output  [4:0] count;  
    reg   [4:0] count; 
    initial count = 5'b10000;

    always @(posedge obf_clk)
        begin
            if (reset)
                count <= 5'b10000;
            else
                count <= {count[3:0], count[4]};
        end  

endmodule
